async function sendEmail(env, { to, subject, text, html }) {
  if (!env.SENDGRID_API_KEY || !env.SENDGRID_FROM_EMAIL) {
    throw new Error("SendGrid not configured");
  }

  const payload = {
    personalizations: [{ to: [{ email: to }] }],
    from: { email: env.SENDGRID_FROM_EMAIL },
    subject,
    content: [],
  };

  if (text) payload.content.push({ type: "text/plain", value: text });
  if (html) payload.content.push({ type: "text/html", value: html });

  const res = await fetch("https://api.sendgrid.com/v3/mail/send", {
    method: "POST",
    headers: {
      Authorization: `Bearer ${env.SENDGRID_API_KEY}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify(payload),
  });

  if (!res.ok) {
    const message = await safeReadText(res);
    throw new Error(`SendGrid error ${res.status}: ${message}`);
  }

  return { status: res.status, message: "Email accepted by SendGrid" };
}

async function createPaymentIntent(env, { amount, currency, metadata }) {
  if (!env.STRIPE_SECRET_KEY) {
    throw new Error("Stripe not configured");
  }

  const params = new URLSearchParams();
  params.append("amount", String(amount));
  params.append("currency", currency);
  for (const [key, value] of Object.entries(metadata || {})) {
    if (value !== undefined && value !== null) {
      params.append(`metadata[${key}]`, String(value));
    }
  }

  const res = await fetch("https://api.stripe.com/v1/payment_intents", {
    method: "POST",
    headers: {
      Authorization: `Bearer ${env.STRIPE_SECRET_KEY}`,
      "Content-Type": "application/x-www-form-urlencoded",
      "Stripe-Version": env.STRIPE_API_VERSION || "2024-06-20",
    },
    body: params.toString(),
  });

  if (!res.ok) {
    const message = await safeReadJsonOrText(res);
    throw new Error(`Stripe error ${res.status}: ${message}`);
  }

  return await res.json();
}

async function parseJsonBody(request) {
  try {
    const data = await request.json();
    return { ok: true, data };
  } catch {
    return {
      ok: false,
      response: jsonResponse({ error: "Invalid JSON body" }, 400),
    };
  }
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      "Content-Type": "application/json; charset=utf-8",
      "Cache-Control": "no-store",
    },
  });
}

async function safeReadText(res) {
  try {
    return await res.text();
  } catch {
    return "";
  }
}

async function safeReadJsonOrText(res) {
  try {
    const json = await res.json();
    return typeof json === "string" ? json : JSON.stringify(json);
  } catch {
    return await safeReadText(res);
  }
}